<?php
// Generated by Cursor prompt — module: Sirket (Department) — date: 2026-03-15

namespace App\Modules\Sirket\Models;

use Illuminate\Database\Eloquent\Model;
use Illuminate\Database\Eloquent\SoftDeletes;
use Illuminate\Database\Eloquent\Relations\BelongsTo;
use Illuminate\Database\Eloquent\Relations\HasMany;
use Illuminate\Database\Eloquent\Collection;

class Department extends Model
{
    use SoftDeletes;

    protected $table = 'departments';

    protected $fillable = [
        'company_id',
        'parent_department_id',
        'name',
        'code',
        'manager_id',
        'metadata',
        'is_active',
        'created_by',
    ];

    protected $casts = [
        'is_active' => 'boolean',
        'metadata'  => 'array',
    ];

    // ─── Relations ───────────────────────────────────────────────────────────

    public function company(): BelongsTo
    {
        return $this->belongsTo(Company::class);
    }

    public function parent(): BelongsTo
    {
        return $this->belongsTo(Department::class, 'parent_department_id');
    }

    public function children(): HasMany
    {
        return $this->hasMany(Department::class, 'parent_department_id');
    }

    /** Tüm alt departmanlar (recursive) */
    public function allChildren(): HasMany
    {
        return $this->children()->with('allChildren');
    }

    public function manager(): BelongsTo
    {
        return $this->belongsTo(\App\Modules\Personel\Models\Personel::class, 'manager_id');
    }

    public function personels(): HasMany
    {
        return $this->hasMany(\App\Modules\Personel\Models\Personel::class);
    }

    public function teams(): HasMany
    {
        return $this->hasMany(Team::class);
    }

    public function createdBy(): BelongsTo
    {
        return $this->belongsTo(\App\Models\User::class, 'created_by');
    }

    // ─── Scopes ──────────────────────────────────────────────────────────────

    public function scopeForCompany($query, int $companyId)
    {
        return $query->where('company_id', $companyId);
    }

    public function scopeActive($query)
    {
        return $query->where('is_active', true);
    }

    public function scopeRoots($query)
    {
        return $query->whereNull('parent_department_id');
    }

    // ─── Helpers ─────────────────────────────────────────────────────────────

    /** Departman ve tüm alt departmanlardaki personel sayısı */
    public function getTotalPersonelCountAttribute(): int
    {
        $ids = $this->getAllChildIds(collect([$this->id]));
        return \App\Modules\Personel\Models\Personel::whereIn('department_id', $ids)
            ->where('is_active', true)
            ->count();
    }

    private function getAllChildIds(Collection $ids): Collection
    {
        $children = static::whereIn('parent_department_id', $ids)->pluck('id');
        if ($children->isEmpty()) return $ids;
        return $ids->merge($this->getAllChildIds($children));
    }

    /** Breadcrumb için tam hiyerarşik yol */
    public function getBreadcrumbAttribute(): string
    {
        $parts = [$this->name];
        $dept  = $this;
        while ($dept->parent_department_id) {
            $dept    = $dept->parent;
            $parts[] = $dept->name;
        }
        return implode(' › ', array_reverse($parts));
    }
}
